package bind

import (
	"io"
	"net/netip"
	"testing"
	"time"

	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/reseq"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// bindSecondPeer constructs a SECOND peerState over the SAME shared sockets an already-Open
// Multipath holds, and binds it into m.peers/m.peersByName. It stands in for the concentrator's
// per-peer wiring (a later G4 task) so this test can exercise the runtime shared-path fan-out
// while >=2 peerStates are bound: it gives the peer its own DynamicScheduler, its own probe
// initiator factory + boot probers (aligned with the durable membership m.defs), and a
// peerPathState VIEW over each currently-bound shared socket. It must run after m.Open.
func bindSecondPeer(t testing.TB, m *Multipath, name string, psk config.Key, clk telemetry.Clock) *peerState {
	t.Helper()
	lg, err := log.New("error", io.Discard)
	if err != nil {
		t.Fatalf("build logger: %v", err)
	}
	cfg := telemetry.ProberConfig{
		LossWindow: 0,
		Liveness:   telemetry.LivenessConfig{DownAfter: testProbeDownAfter, UpAfterSuccesses: testProbeUpSucc},
	}
	// A DISTINCT probe session id from the primary's: a concentrator peer runs its own probe
	// session, and it proves the fan-out mints genuinely per-peer probers (not shared handles).
	const secondPeerSessionID uint64 = 0x0123456789ABCDEF
	newProber := func(pname string, id uint8) *telemetry.Prober {
		return telemetry.NewProber(pname, id, secondPeerSessionID, psk, cfg, clk, lg)
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	// Boot probers aligned with the durable membership (m.defs), stamped with each shared
	// socket's path-id so DATA and PROBE agree on the wire, exactly as Open does for the primary.
	probers := make([]*telemetry.Prober, len(m.defs))
	health := make([]sched.PathHealth, len(m.defs))
	byName := make(map[string]*telemetry.Prober, len(m.defs))
	for i := range m.defs {
		var id uint8
		for _, sp := range m.shared {
			if sp.name == m.defs[i].Name {
				id = sp.id
			}
		}
		probers[i] = newProber(m.defs[i].Name, id)
		health[i] = probers[i]
		byName[m.defs[i].Name] = probers[i]
	}
	scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Hour}, clk, lg)
	if err != nil {
		t.Fatalf("build second-peer scheduler: %v", err)
	}
	// Build the peer through the SAME seam production uses (newPeerState), so its Reflector
	// and every codec derive from THIS peer's psk (T84) rather than being hand-wired.
	p := newPeerState(name, psk, scheduler, newProber, probers)
	sendCodec, err := p.newCodec()
	if err != nil {
		t.Fatalf("build second-peer send codec: %v", err)
	}
	p.sendCodec = sendCodec
	// A per-peer receive resequencer, exactly as Open Stores for the primary — the
	// concentrator's per-peer wiring (a later G4 task) builds this; the helper stands in
	// so handleInbound can route this peer's DATA stream into its OWN buffer and the
	// engine-facing drainer can release it under this peer's virtual endpoint.
	p.resequencer.Store(reseq.New(resequencerWindow, resequencerTimeout, reseq.SystemClock{}))
	// A peerPathState VIEW over each bound shared socket, index-aligned with m.shared (which,
	// with no deferred paths, is also aligned with m.defs) so the peer's scheduler and paths
	// stay index-aligned exactly as the primary's do.
	for _, sp := range m.shared {
		codec, cerr := p.newCodec()
		if cerr != nil {
			t.Fatalf("build second-peer path codec: %v", cerr)
		}
		pp := &peerPathState{sharedPathState: sp, peer: p, codec: codec, prober: byName[sp.name]}
		p.paths = append(p.paths, pp)
		// Publish this peer's view for the receive demux, exactly as the concentrator's per-peer
		// wiring does, so handleInbound source-demuxes the shared socket to the owning peer (T88).
		sp.addViewLocked(pp)
	}
	m.peers = append(m.peers, p)
	m.peersByName[name] = p
	// Register the peer's virt so an outbound Send to it routes to THIS peerState (the
	// concentrator's per-peer wiring does the same when it binds a peer).
	m.peerByVirt[p.virt] = p
	// Republish the lock-free peer view the receive drainer iterates, so this newly-bound
	// peer's resequencer is drained (mirrors the concentrator wiring's obligation).
	m.republishPeersLocked()
	return p
}

// pathNamesOfPeer snapshots a peer's per-(peer,path) view names, for assertions.
func pathNamesOfPeer(p *peerState) []string {
	out := make([]string, len(p.paths))
	for i, pp := range p.paths {
		out[i] = pp.name
	}
	return out
}

// peerPathByName returns the peer's per-(peer,path) view of the named shared path, or nil.
func peerPathByName(p *peerState, name string) *peerPathState {
	for _, pp := range p.paths {
		if pp.name == name {
			return pp
		}
	}
	return nil
}

// TestMultipathSharedPathFanOutAcrossPeers is the G4 fan-out acceptance for the peerState /
// pathState split: with TWO peerStates bound over the same shared sockets, a runtime AddPath of
// a SHARED path must instantiate per-(peer,path) state (codec, remote, prober, tx/rx) for BOTH
// peers, and a runtime RemovePath must tear that per-(peer,path) state down for BOTH peers,
// leaving each peer's remaining paths untouched. It proves the fan-out has a single owner
// (attachSharedPathLocked / RemovePath) exercised while >=2 peerStates exist.
func TestMultipathSharedPathFanOutAcrossPeers(t *testing.T) {
	psk := testKey(t, 0x41)
	clk := newFakeClock()
	m, _, _ := newProbingMultipath(t, loopbackPaths(1), psk, clk) // one shared path, "a"
	if _, _, err := m.Open(0); err != nil {
		t.Fatalf("Open: %v", err)
	}
	t.Cleanup(func() { _ = m.Close() })

	primary := m.peerState
	second := bindSecondPeer(t, m, "peer-2", psk, clk)

	// Preconditions: two bound peers, each with exactly the one boot path "a" over the one
	// shared socket. Capture each peer's original path object to prove the remove leaves it
	// untouched.
	if len(m.peers) != 2 {
		t.Fatalf("bound peers = %d, want 2", len(m.peers))
	}
	if len(m.shared) != 1 {
		t.Fatalf("shared sockets = %d, want 1", len(m.shared))
	}
	primaryOrigA := peerPathByName(primary, "a")
	secondOrigA := peerPathByName(second, "a")
	if primaryOrigA == nil || secondOrigA == nil {
		t.Fatalf("boot path 'a' missing: primary=%v second=%v", pathNamesOfPeer(primary), pathNamesOfPeer(second))
	}
	if primaryOrigA.sharedPathState != secondOrigA.sharedPathState {
		t.Fatal("the two peers' boot path 'a' must VIEW the same shared socket")
	}

	// --- AddPath a SHARED path at runtime: the fan-out must reach BOTH peers. ---
	if err := m.AddPath(config.Path{Name: "shared-b", SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
		t.Fatalf("AddPath: %v", err)
	}
	if len(m.shared) != 2 {
		t.Fatalf("shared sockets after add = %d, want 2", len(m.shared))
	}
	sharedB := m.shared[1]
	if sharedB.name != "shared-b" {
		t.Fatalf("new shared socket name = %q, want %q", sharedB.name, "shared-b")
	}

	for _, tc := range []struct {
		who string
		p   *peerState
	}{{"primary", primary}, {"second", second}} {
		pp := peerPathByName(tc.p, "shared-b")
		if pp == nil {
			t.Fatalf("%s peer has no per-(peer,path) state for 'shared-b' after add (fan-out missed it): %v", tc.who, pathNamesOfPeer(tc.p))
		}
		// Per-(peer,path) state was instantiated: its OWN codec + prober, VIEWING the ONE shared
		// socket (not a duplicate socket per peer).
		if pp.sharedPathState != sharedB {
			t.Fatalf("%s peer's 'shared-b' does not view the shared socket (per-peer socket duplicated)", tc.who)
		}
		if pp.codec == nil {
			t.Fatalf("%s peer's 'shared-b' has no per-(peer,path) codec", tc.who)
		}
		if pp.prober == nil {
			t.Fatalf("%s peer's 'shared-b' has no per-(peer,path) prober", tc.who)
		}
		if pp.peer != tc.p {
			t.Fatalf("%s peer's 'shared-b' back-references the wrong peerState", tc.who)
		}
	}
	// The two peers minted DISTINCT probers for the shared path (genuine per-(peer,path) state,
	// not one shared handle).
	if peerPathByName(primary, "shared-b").prober == peerPathByName(second, "shared-b").prober {
		t.Fatal("both peers share ONE prober for 'shared-b' — the fan-out did not mint per-peer state")
	}

	// --- RemovePath the shared path: the teardown must reach BOTH peers. ---
	if err := m.RemovePath("shared-b"); err != nil {
		t.Fatalf("RemovePath: %v", err)
	}
	if len(m.shared) != 1 {
		t.Fatalf("shared sockets after remove = %d, want 1", len(m.shared))
	}
	for _, tc := range []struct {
		who  string
		p    *peerState
		orig *peerPathState
	}{{"primary", primary, primaryOrigA}, {"second", second, secondOrigA}} {
		if peerPathByName(tc.p, "shared-b") != nil {
			t.Fatalf("%s peer still holds per-(peer,path) state for 'shared-b' after remove: %v", tc.who, pathNamesOfPeer(tc.p))
		}
		if len(tc.p.paths) != 1 {
			t.Fatalf("%s peer path count after remove = %d, want 1 (remaining paths untouched)", tc.who, len(tc.p.paths))
		}
		remaining := peerPathByName(tc.p, "a")
		if remaining == nil {
			t.Fatalf("%s peer lost its remaining path 'a' on the remove: %v", tc.who, pathNamesOfPeer(tc.p))
		}
		if remaining != tc.orig {
			t.Fatalf("%s peer's remaining path 'a' object changed on the remove (remaining paths must be untouched)", tc.who)
		}
	}
}

	// A fresh resequencer per Open: its release point re-pins to the first frame THIS peer
	// receives after this bring-up, so a Close→Open cycle (or reconnect) never wedges on a
	// stale high-water outer-seq. Published atomically so the peer's per-path readLoop
	// goroutines read it WITHOUT m.mu.
	ps.resequencer.Store(reseq.New(resequencerWindow, resequencerTimeout, reseq.SystemClock{}))

	// Fresh FEC send/receive state per Open, when FEC is enabled (T24). The encoder
	// group state and the decoder's per-group buffers re-pin with the sockets, so a
	// Close→Open cycle never reconstructs against a stale group. Both are torn down (per
	// peer) in closeSocketsLocked. A build error here is a programmer error (the ratio was
	// validated in NewMultipath), so it fails the Open.
	if m.fecCfg != nil {
		enc, err := fec.NewEncoder(*m.fecCfg, fec.SystemClock{})
		if err != nil {
			return fmt.Errorf("bind: build FEC encoder: %w", err)
		}
		dec, err := fec.NewDecoder(*m.fecCfg)
		if err != nil {
			return fmt.Errorf("bind: build FEC decoder: %w", err)
		}
		dec.SetRetainWindow(fecRetainGroups)
		// Quiescence-accurate unrecoverable accounting (D24): fold a doomed group into
		// the unrecoverable counter once its recovery could no longer have helped, even
		// when no newer group arrives to advance the retain-window eviction (a stalled
		// link, or traffic that simply stops after an incident). Past fecRecoveryDeadline
		// from a group's first-seen instant, its deadline-flushed parity has certainly
		// arrived (encoder grouping deadline) AND the resequencer has certainly skipped
		// its gap (resequencerTimeout), so any later reconstruction is delivered too late
		// to matter — the group is definitively unrecoverable and safe to count.
		dec.SetClock(fec.SystemClock{})
		dec.SetRecoveryDeadline(m.fecCfg.Deadline + resequencerTimeout)
		ps.fecSend = &fecSender{enc: enc}
		// Adaptive mode (T29): a fresh controller per Open, re-pinned with the encoder so a
		// Close→Open cycle starts the control law from M=0 (no standing redundancy until
		// loss is observed) rather than inheriting a stale target. The controller cfg was
		// validated in NewMultipath, so a build error here is a programmer error and fails
		// the Open. The receive-side residual-loss estimator (post-FEC-recovery loss, the
		// P4 signal) is likewise fresh per span.
		if m.adaptiveCfg != nil {
			ctrl, err := adaptivefec.NewController(*m.adaptiveCfg, adaptivefec.SystemClock{})
			if err != nil {
				return fmt.Errorf("bind: build adaptive FEC controller: %w", err)
			}
			ps.fecSend.ctrl = ctrl
			// Adopt the controller's starting parity (0 — no standing redundancy until loss
			// is observed) so the encoder and controller agree from t=0; the tick loop then
			// sizes it to measured loss within the first control interval. Fixed mode leaves
			// the encoder at its cfg.ParityShards default instead.
			enc.SetParity(ctrl.Parity())
		}
		ps.fecRecv.Store(&fecReceiver{dec: dec, connLoss: telemetry.NewConnLoss(fecResidualLossWindow)})
	}
	ps.sendCodec = sendCodec
	return nil
}

// readLoop is one Bind-OWNED per-path receive goroutine (T30). It reads the path
// socket and dispatches every datagram through handleInbound — which pushes DATA
// into the shared resequencer and answers/consumes PROBEs — then pokes the delivery
// signal so the single engine-facing drainer wakes to release any newly in-order
// frame. The read buffer is private to this goroutine, so the per-path Codec's
// scratch is never shared.
//
// Owning the readers in the Bind (rather than returning one ReceiveFunc per path to
// the engine, as T12 did) is what makes a runtime path add/remove possible without
// disturbing the engine: the engine builds its receive goroutines ONCE from Open's
// return, so a path added later gets a reader HERE while the engine's fixed receive
// set — and thus the WG session — sees no churn. The goroutine exits when its socket
// is closed (RemovePath drains one path; Close drains all).
func (m *Multipath) readLoop(ps *peerPathState, deliver chan<- struct{}) {

func (m *Multipath) Close() error {
	m.mu.Lock()
	defer m.mu.Unlock()
	// Release the fan-in first so any reader parked on a delivery poke, and the
	// engine-facing drainer, unblock; then close the sockets so every readLoop
	// returns; then wait for them all to exit before clearing state so no reader
	// outlives this Close (and no reader touches the resequencer a later Open
	// replaces). readLoop needs no lock, so waiting under m.mu cannot deadlock.
	if m.recvClosed != nil {
		close(m.recvClosed)
	}
	err := m.closeSocketsLocked()
	m.readersWG.Wait()
	m.deliverSignal = nil
	m.recvClosed = nil
	return err
}

// closeSocketsLocked closes all path sockets and resets the bind to the unopened
// state (paths and send Codec cleared), returning the first close error. Caller
// holds m.mu. Idempotent: safe on an already-closed or never-opened bind — which
// is exactly what the engine's pre-open Close relies on.
func (m *Multipath) closeSocketsLocked() error {
	var firstErr error
	// Sockets are SHARED (one per shared path), so close them once from the shared list —
	// NOT once per (peer,path) view, which would double-close a concentrator socket.
	for _, sp := range m.shared {
		if sp.conn != nil {
			if err := sp.conn.Close(); err != nil && firstErr == nil {
				firstErr = err
			}
		}
	}
	m.shared = nil
	m.deferred = nil
	// Clear every peer's per-Open state so the next Open rebuilds it fresh (paths, send
	// Codec, FEC send/receive). The deadline-tick goroutine that reads a peer's fecSend is
	// stopped by Close (recvClosed) and joined via readersWG before state is cleared, and it
	// captured its own fecSender pointer, so niling here never races it.
	for _, p := range m.peers {
		p.paths = nil
		p.sendCodec = nil
		p.fecSend = nil
		p.fecRecv.Store(nil)
	}
	return firstErr
}

// AddPath admits a new path to the running bond at runtime (T30): it binds the
// path's source-addr'd socket, mints its prober (via the injected factory) joining
// the current probe session, seeds its remote from the config dest_addr or the
// learned default, admits it to the scheduler as a NEW LOWEST-PRIORITY path, and
// spawns its Bind-owned reader. Everything runs under m.mu, so the path slice and
// the scheduler's path list are mutated together and stay index-aligned as Send
// observes them (Send also holds m.mu). The new path starts DOWN (its prober has no
// echoes yet) and is only selected once its probes report healthy, so admission
// disturbs neither the active selection of the surviving paths nor the WG session:
// the single virtual endpoint is untouched, and the engine's receive set does not
// change (the reader is the Bind's, not the engine's).
//
// Path-ids are handed out monotonically from a high-water counter that persists
// ACROSS Open spans (a Close->Open cycle does NOT reset it -- only a process restart
// does), so a surviving path is never renumbered and a reopened bond never re-mints
// an id the peer still associates with old per-path reflector state; the uint8 id
// space (256 ids) is therefore consumed CUMULATIVELY over the process lifetime by
// the initial-Open admissions (the N configured paths take ids 0..N-1) PLUS every
// runtime AddPath admission combined, and is exhausted once 256 distinct ids have
// been minted over the daemon's life, which fails fast rather than reusing an id and
// colliding with the peer's per-path reflector state.
