112	// TestMultipathReflectsProbe: an authenticated inbound PROBE (IsEcho=false) is
113	// reflected verbatim (same ProbeSeq/TimestampNanos, IsEcho now true) back to its
114	// source, and the path learns that source as its return remote (D11).
115	func TestMultipathReflectsProbe(t *testing.T) {
116		psk := testKey(t, 0x21)
117		clk := newFakeClock()
118		m, _, _ := newProbingMultipath(t, loopbackPaths(1), psk, clk)
119		if _, _, err := m.Open(0); err != nil {
120			t.Fatalf("Open: %v", err)
121		}
122		t.Cleanup(func() { _ = m.Close() })
123	
